// Solution
function sortArray(arr, length) {
  if (length <= 1) return;
  let pivot = arr[Math.floor(length / 2)];
  let left = [];
  let right = [];
  for (let i = 0; i < length; i++) {
    if (arr[i] < pivot) {
      left.push(arr[i]);
    } else if (arr[i] > pivot) {
      right.push(arr[i]);
    }
  }
  sortArray(left, left.length);
  sortArray(right, right.length);
  arr.splice(0, arr.length, ...left, pivot, ...right);
}
